    public static void spiralFill(int m, int n, int[][] a) {
        int val = 1;
        int k = 0, l = 0;
        int currentM = m;
        int currentN = n;
        while (k < currentM && l < currentN) {
            // Fill the top row
            for (int i = l; i < currentN; i++) {
                a[k][i] = val;
                val++;
            }
            k++;
            // Fill the right column
            for (int i = k; i < currentM; i++) {
                a[i][currentN - 1] = val;
                val++;
            }
            currentN--;
            // Fill the bottom row if available
            if (k < currentM) {
                for (int i = currentN - 1; i >= l; i--) {
                    a[currentM - 1][i] = val;
                    val++;
                }
                currentM--;
            }
            // Fill the left column if available
            if (l < currentN) {
                for (int i = currentM - 1; i >= k; i--) {
                    a[i][l] = val;
                    val++;
                }
                l++;
            }
        }
    }

