    public static String decimalToBinary(double num, int k_prec) {
        StringBuilder binary = new StringBuilder();
        // Separate integral and fractional parts
        int integral = (int) num;
        double fractional = num - integral;
        // Convert integral part to binary
        if (integral == 0) {
            binary.append("0");
        } else {
            while (integral > 0) {
                int rem = integral % 2;
                binary.append(rem);
                integral /= 2;
            }
            binary.reverse();
        }
        binary.append('.');
        // Convert fractional part to binary
        for (int i = 0; i < k_prec; i++) {
            fractional *= 2;
            int fractBit = (int) fractional;
            if (fractBit == 1) {
                fractional -= fractBit;
                binary.append('1');
            } else {
                binary.append('0');
            }
        }
        return binary.toString();
    }

