    public static long countBT(int h) {
        final long MOD = 1000000007L;
        if (h == 0) return 1;
        long[] dp = new long[h + 1];
        dp[0] = 1;
        dp[1] = 1;
        for (int i = 2; i <= h; i++) {
            long term = (2 * dp[i - 2]) % MOD;
            dp[i] = (dp[i - 1] * (term + dp[i - 1]) % MOD) % MOD;
        }
        return dp[h];
    }

