    public static int numOfIncSubseqOfSizeK(int[] arr, int n, int k) {
        // Create a 2D dp array with dimensions k x n
        int[][] dp = new int[k][n];
        // Initialize the first row to 1
        for (int i = 0; i < n; i++) {
            dp[0][i] = 1;
        }
        // Fill dp for subsequences of length l+1 (from 1 to k-1)
        for (int l = 1; l < k; l++) {
            for (int i = l; i < n; i++) {
                dp[l][i] = 0;
                // Iterate j from l-1 to i-1 (inclusive)
                for (int j = l - 1; j < i; j++) {
                    if (arr[j] < arr[i]) {
                        dp[l][i] += dp[l - 1][j];
