    public static int eggDrop(int n, int k) {
        // Create a 2D DP table where eggFloor[i][j] represents minimum trials for i eggs and j floors
        int[][] eggFloor = new int[n + 1][k + 1];
        // Base cases:
        // For 0 floors: 0 trials needed
        // For 1 floor: always 1 trial needed
        for (int i = 1; i <= n; i++) {
            eggFloor[i][0] = 0; // 0 floors
            eggFloor[i][1] = 1; // 1 floor
        }
        // With only 1 egg, we need j trials for j floors
        for (int j = 1; j <= k; j++) {
            eggFloor[1][j] = j;
        }
        // Fill DP table for 2+ eggs and 2+ floors
        for (int i = 2; i <= n; i++) {          // Eggs from 2 to n
            for (int j = 2; j <= k; j++) {      // Floors from 2 to k
                eggFloor[i][j] = Integer.MAX_VALUE;
                // Consider all drops from 1st to jth floor
                for (int x = 1; x <= j; x++) {
                    // If egg breaks: check below floors (i-1 eggs, x-1 floors)
                    // If egg doesn't break: check above floors (i eggs, j-x floors)
                    int res = 1 + Math.max(eggFloor[i - 1][x - 1], eggFloor[i][j - x]);
                    if (res < eggFloor[i][j]) {
                        eggFloor[i][j] = res;
                    }
                }
            }
        }
        return eggFloor[n][k];
    }

