                    if (oper[k] == '&') {
                        T[i][j] += T[i][k] * T[k+1][j];
                        F[i][j] += (tik * tkj - T[i][k] * T[k+1][j]);
                    } else if (oper[k] == '|') {
                        F[i][j] += F[i][k] * F[k+1][j];
                        T[i][j] += (tik * tkj - F[i][k] * F[k+1][j]);
