    public static int MinimumCost(int[] cost, int n, int W) {
        final int INF = Integer.MAX_VALUE / 2; // Avoid overflow
        List<Integer> val = new ArrayList<>();
        List<Integer> wt = new ArrayList<>();
        int size = 0;
        for (int i = 0; i < n; i++) {
            if (cost[i] != -1) {
                val.add(cost[i]);
                wt.add(i + 1);
                size++;
            }
        }
        n = size; // Update n to available packets count
        int[][] min_cost = new int[n + 1][W + 1];
        // Initialize base cases
        for (int j = 1; j <= W; j++) {
            min_cost[0][j] = INF;
        }
        for (int i = 1; i <= n; i++) {
            min_cost[i][0] = 0;
        }
        // Fill DP table
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= W; j++) {
                int currentWt = wt.get(i - 1);
                if (currentWt > j) {
                    min_cost[i][j] = min_cost[i - 1][j];
                } else {
                    int take = min_cost[i][j - currentWt];
                    if (take != INF) {
                        take += val.get(i - 1);
                    }
                    min_cost[i][j] = Math.min(min_cost[i - 1][j], take);
                }
            }
        }
        return min_cost[n][W] == INF ? -1 : min_cost[n][W];
    }

