    public static int minJumps(int arr[], int n) {
        int[] jumps = new int[n];
        // Initialize the last element as 0 because we are already at the end
        jumps[n-1] = 0;
        // Process the array from the second last element backwards
        for (int i = n-2; i >= 0; i--) {
            if (arr[i] == 0) {
                // If the current element is 0, it can't jump forward
                jumps[i] = Integer.MAX_VALUE;
            } else if (arr[i] >= n - i - 1) {
                // If the current element can jump directly to the end
                jumps[i] = 1;
            } else {
                int min = Integer.MAX_VALUE;
                // Look at the next arr[i] elements to find the minimum jump
                for (int j = i+1; j < n && j <= arr[i] + i; j++) {
                    if (min > jumps[j]) {
                        min = jumps[j];
                    }
                }
                // If we found a reachable path
                if (min != Integer.MAX_VALUE) {
                    jumps[i] = min + 1;
                } else {
                    jumps[i] = min; // remains MAX_VALUE (unreachable)
                }
            }
        }
        return jumps[0];
    }

