    public static int minimumBox(int[] arr, int n) {
        // If n is 0, return 0 to avoid index issues
        if (n == 0) return 0;
        // Create a copy of the first n elements and sort
        int[] sortedArr = Arrays.copyOf(arr, n);
        Arrays.sort(sortedArr);
        Deque<Integer> q = new ArrayDeque<>();
        q.add(sortedArr[0]);
        for (int i = 1; i < n; i++) {
            int now = q.peekFirst();
            if (sortedArr[i] >= 2 * now) {
                q.pollFirst();
            }
            q.add(sortedArr[i]);
        }
        return q.size();
    }

