    public static int maximumNumberDistinctPrimeRange(int m, int n) {
        int[] factorCount = new int[n + 1];
        boolean[] prime = new boolean[n + 1];
        // Initialize arrays
        for (int i = 0; i <= n; i++) {
            factorCount[i] = 0;
            prime[i] = true;
        }
        // Sieve of Eratosthenes modified to count distinct prime factors
        for (int i = 2; i <= n; i++) {
            if (prime[i]) {
                factorCount[i] = 1; // i is prime, so one distinct prime factor
                for (int j = i * 2; j <= n; j += i) {
                    factorCount[j]++; // j has i as a distinct prime factor
                    prime[j] = false; // j is not prime
                }
            }
        }
        // Find the number in range [m, n] with max distinct prime factors
        int max = factorCount[m];
        int num = m;
        for (int i = m + 1; i <= n; i++) {
            if (factorCount[i] > max) {
                max = factorCount[i];
                num = i;
            }
        }
        return num;
    }

