    public static void rearrange(int[] a, int size) {
        int positive = 0;
        int negative = 1;
        while (true) {
            // Move positive pointer to next invalid positive at even index
            while (positive < size && a[positive] >= 0) {
                positive += 2;
            }
            // Move negative pointer to next invalid negative at odd index
            while (negative < size && a[negative] <= 0) {
                negative += 2;
            }
            // Swap if both pointers are within bounds
            if (positive < size && negative < size) {
                int temp = a[positive];
                a[positive] = a[negative];
                a[negative] = temp;
            } else {
                // Exit if either pointer goes out of bounds
                break;
            }
        }
    }

