    public static int find_maximum(int[] a, int n, int k) {
        HashMap<Integer, Integer> map = new HashMap<>();
        for (int i = 0; i < n; i++) {
            int x = a[i];
            int d = Math.min(1 + i, n - i);
            Integer current = map.get(x);
            if (current == null) {
                map.put(x, d);
            } else {
                if (d < current) {
                    map.put(x, d);
                }
            }
        }
        int ans = Integer.MAX_VALUE;
        for (int i = 0; i < n; i++) {
            int x = a[i];
            int complement = k - x;
            if (x != complement) {
                Integer compValue = map.get(complement);
                if (compValue != null) {
                    int candidate = Math.max(map.get(x), compValue);
                    if (candidate < ans) {
                        ans = candidate;
                    }
                }
            }
        }
        return ans;
    }

