    public static long sumofsquare(int n) {
        long[][] C = new long[n + 1][n + 1];
        for (int i = 0; i <= n; i++) {
            int min = Math.min(i, n);
            for (int j = 0; j <= min; j++) {
                if (j == 0 || j == i) {
                    C[i][j] = 1;
                } else {
                    C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
                }
            }
        }
        long sum = 0;
        for (int i = 0; i <= n; i++) {
            sum += C[n][i] * C[n][i];
        }
        return sum;
    }

