public static int offeringNumber(int n, int[] templeHeight) {
    int sum = 0;
    for (int i = 0; i < n; i++) {
        int left = 0;
        for (int j = i - 1; j >= 0; j--) {
            if (templeHeight[j] < templeHeight[j + 1]) {
                left++;
            } else {
                break;
            }
        }
        int right = 0;
        for (int j = i + 1; j < n; j++) {
            if (templeHeight[j] < templeHeight[j - 1]) {
                right++;
            } else {
                break;
            }
        }
        sum += Math.max(left, right) + 1;
    }
    return sum;
}

